import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const y=JSON.parse('{"title":"LinkedQL — Universal Database Contract for Applications & Agents","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),l={name:"overview.md"};function o(i,a,p,r,c,d){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="linkedql-—-universal-database-contract-for-applications-agents" tabindex="-1">LinkedQL <br>— Universal Database Contract for Applications &amp; Agents <a class="header-anchor" href="#linkedql-—-universal-database-contract-for-applications-agents" aria-label="Permalink to &quot;LinkedQL &lt;br&gt;— Universal Database Contract for Applications &amp; Agents&quot;">​</a></h1><p><strong>Welcome to the docs.</strong> This page is the conceptual narrative of LinkedQL — the core thinking, the problem space it addresses, and the architectural model it introduces. It is not a setup guide. If you&#39;re here to get running, jump straight to the <a href="/guides">Core Guides</a>.</p><hr><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>LinkedQL is in active development. The core query model and interfaces are stabilizing and backed by 1,200+ tests. MySQL/MariaDB live query support is still in progress. Feedback, issues, and PRs are welcome — see <a href="https://github.com/linked-db/linked-ql#-contributing" target="_blank" rel="noreferrer">Contributing</a>; see <a href="https://github.com/linked-db/linked-ql/issues" target="_blank" rel="noreferrer">Issues</a>.</p></div><hr><h2 id="what-is-linkedql" tabindex="-1">What is LinkedQL? <a class="header-anchor" href="#what-is-linkedql" aria-label="Permalink to &quot;What is LinkedQL?&quot;">​</a></h2><p>LinkedQL is a universal database contract for applications.</p><p>Traditionally, applications rely on several different systems to maintain their relationship with the database.</p><p>LinkedQL moves those concerns into a unified query model – <strong>formalizing</strong> the application-database relationship at the query boundary, and making the whole model a <strong>universal contract</strong>.</p><hr><h2 id="why-linkedql" tabindex="-1">Why LinkedQL <a class="header-anchor" href="#why-linkedql" aria-label="Permalink to &quot;Why LinkedQL&quot;">​</a></h2><p>Every application that has the database as a dependency suffers the same underlying issue: no proper way to express and enforce critical aspects of that relationship.</p><ul><li>the application object model must be manually constructed from relational data – object-relational mapping</li><li>state synchronization requires secondary infrastructure – subscription servers, sync engines</li><li>schema changes require manual coordination</li><li>deployment topology leaks into application logic</li></ul><p>In each case, applications are forced to compensate via secondary infrastructure and human effort.</p><p>LinkedQL was created to formalize that relationship at the query boundary and make it self-enforcing.</p><p>Live queries, synchronization, version safety, federation, and object-relational traversal emerge from that model.</p><hr><h2 id="the-application-database-relationship-–-formalized" tabindex="-1">The Application-Database Relationship – Formalized <a class="header-anchor" href="#the-application-database-relationship-–-formalized" aria-label="Permalink to &quot;The Application-Database Relationship – Formalized&quot;">​</a></h2><p>Each part of the LinkedQL model maps to an aspect of that relationship – expressed more properly:</p><ul><li>object-relational syntax – <strong>the application object model formalized at the query boundary</strong> – rather than moved to a post-processing step: application-level data assembly lines, object-relational mapping (ORM)</li><li>live queries, subscriptions, and sync – <strong>state convergence formalized at the query boundary</strong> – rather than handled via secondary infrastructure: API servers, subscription services, dedicated sync engines</li><li>version safety – <strong>schema assumptions formalized at the query boundary</strong> – rather than handled via manual coordination, on a best-effort basis, or compensated through runtime failures</li></ul><p>Applications simply <em>operate by contract</em> (formal spec) – and effectively stay decoupled from implementation details.</p><p>LinkedQL makes the contract self-enforcing.</p><p><strong><em>Before</em>:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>Application  ⇄  [ ORM                     ]  ⇄  Database</span></span>
<span class="line"><span>                [ Realtime Infrastructure ]</span></span>
<span class="line"><span>                [ Sync Infrastructure     ]</span></span>
<span class="line"><span>                [ Manual Lifecycle        ]</span></span>
<span class="line"><span>                  Coordination</span></span></code></pre></div><p><strong><em>After</em>:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>Application  ⇄  [ db.query(sql)           ]  ⇄  Database</span></span></code></pre></div><p><strong><em>Example</em>:</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// A live query – with relationship traversal</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT {</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    profile: { name, email },</span></span>
<span class="line"><span style="color:#C3E88D;">    parent: parent_user ~&gt; { name, email }</span></span>
<span class="line"><span style="color:#C3E88D;">  } FROM users;</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="the-whole-model-as-a-universal-contract" tabindex="-1">The Whole Model As a Universal Contract <a class="header-anchor" href="#the-whole-model-as-a-universal-contract" aria-label="Permalink to &quot;The Whole Model As a Universal Contract&quot;">​</a></h2><p>LinkedQL works across dialects:</p><ul><li>PostgreSQL, MySQL/MariaDB</li></ul><p>across environments:</p><ul><li>server, browser, edge, worker – via EdgeClient</li></ul><p>and is embeddable as local database:</p><ul><li>FlashQL</li></ul><p>The same interface (<code>db.query()</code>) and capabilities apply whether the database is a local dependency or remote dependency, regardless of runtime environment or storage engine.</p><p>Applications simply commit to a standard contract that everything else can sit behind.</p><p><strong><em>Before</em>:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>1. Server-Side Application  ⇄  [ ORM                     ]  ⇄  Database</span></span>
<span class="line"><span>                               [ Realtime Infrastructure ]</span></span>
<span class="line"><span>                               [ Sync Infrastructure     ]</span></span>
<span class="line"><span>                               [ Manual Lifecycle        ]</span></span>
<span class="line"><span>                                 Coordination</span></span>
<span class="line"><span>2. Client-Side Application  ⇄  [ API Server              ]  ⇄  Database</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>3. Local-First Application  ⇄  [ db.query(sql)           ]  ⇄  Database</span></span>
<span class="line"><span>                                                        (Local SQLite, PGLite, etc.)</span></span></code></pre></div><p><strong><em>After</em>:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>                                      [ 1. Native Connection + Database ]</span></span>
<span class="line"><span>Application  ⇄  [ db.query(sql) ]  ⇄  [ 2. Edge Protocol + Database     ]</span></span>
<span class="line"><span>                                      [ 3. Local Database (FlashQL)     ]</span></span></code></pre></div><p><strong><em>Example</em>:</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// Server-side environment only</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">    // or MySQLClient/MariaDBClient</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Any environment – runs anywhere: server, browser, worker, edge</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">     // Local database    </span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">  // Remote querying</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Consistent application logic</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT { id, profile: { name, email } } FROM users;</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>With the conceptual model in context, the next step is getting started.</p><p>The <a href="/guides">Core Guides</a> take you through from installation to running your first query.</p><h2 id="your-map-to-the-docs" tabindex="-1">Your Map to the Docs <a class="header-anchor" href="#your-map-to-the-docs" aria-label="Permalink to &quot;Your Map to the Docs&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Area</th><th style="text-align:left;">What it covers</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">Core Guides</td><td style="text-align:left;">From basic setup to first queries, to more comprehensive guides</td><td style="text-align:left;"><a href="/guides">Core Guides</a></td></tr><tr><td style="text-align:left;">Core API</td><td style="text-align:left;">Core API contract — the interface and query model</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr><tr><td style="text-align:left;">Language Surface</td><td style="text-align:left;">The LinkedQL language surface (JSON Literals, DeepRefs, etc.)</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr><tr><td style="text-align:left;">Realtime Capabilities</td><td style="text-align:left;">Live queries and subscription model</td><td style="text-align:left;"><a href="/realtime">Realtime Capabilities</a></td></tr><tr><td style="text-align:left;">FlashQL</td><td style="text-align:left;">LinkedQL&#39;s embeddable SQL engine for local execution, federation, and sync</td><td style="text-align:left;"><a href="/flashql">FlashQL</a></td></tr></tbody></table>`,51)])])}const u=e(l,[["render",o]]);export{y as __pageData,u as default};
